4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a live cell alive with exactly 2 neighbors (survival)", () => {
18	    // Three cells in a horizontal line - center cell (1,0) has exactly 2 neighbors
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
20	    // Center cell (1,0) survives with 2 neighbors
21	    expect(result).toContainEqual([1, 0]);
22	  });
23	  it("should keep a live cell alive with exactly 3 neighbors (survival)", () => {
24	    // Cell (1,0) has exactly 3 neighbors: (0,0), (2,0), (1,1)
25	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
26	    expect(result).toContainEqual([1, 0]);
27	  });
28	  it("should kill a live cell with 4 neighbors (overpopulation)", () => {
29	    // Center cell (1,1) has 4 live neighbors → dies
30	    const result = nextGeneration([[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]]);
31	    expect(result).not.toContainEqual([1, 1]);
32	  });
33	  it("should bring a dead cell to life with exactly 3 live neighbors (reproduction)", () => {
34	    // Dead cell (1,1) has exactly 3 live neighbors: (0,0), (1,0), (0,1) → born
35	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
36	    expect(result).toContainEqual([1, 1]);
37	  });
38	  it.todo("should keep a block pattern unchanged (still life)");
39	  it.todo("should oscillate a blinker pattern (horizontal to vertical)");
40	});
